import { formatNumber } from '@/lib/format'

interface IndicatorsGridProps {
  indicators?: Record<string, number>
}

export default function IndicatorsGrid({ indicators }: IndicatorsGridProps) {
  const entries = Object.entries(indicators ?? {})

  if (!entries.length) {
    return (
      <div className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-6 text-sm text-zinc-400">
        Sin indicadores disponibles.
      </div>
    )
  }

  return (
    <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
      {entries.map(([key, value]) => (
        <div
          key={key}
          className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-5 shadow-lg shadow-black/20"
        >
          <div className="text-xs uppercase tracking-[0.12em] text-zinc-500">
            {key.replaceAll('_', ' ')}
          </div>
          <div className="mt-3 text-2xl font-semibold text-white">
            {formatNumber(value)}
          </div>
        </div>
      ))}
    </div>
  )
}
