'use client'

import {
  Bar,
  BarChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts'

interface Scenario {
  name: string
  description: string
  assumptions?: string[]
  projectedImpact: Record<string, number>
}

export default function ScenarioComparison({ scenarios }: { scenarios?: Scenario[] }) {
  if (!scenarios?.length) {
    return (
      <div className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-6 text-sm text-zinc-400">
        Sin escenarios disponibles.
      </div>
    )
  }

  const metricKeys = Object.keys(scenarios[0].projectedImpact ?? {})
  const chartData = metricKeys.map((metric) => {
    const row: Record<string, string | number> = {
      metric: metric.replaceAll('_', ' '),
    }

    scenarios.forEach((scenario) => {
      row[scenario.name] = Number(scenario.projectedImpact[metric]?.toFixed?.(2) ?? scenario.projectedImpact[metric] ?? 0)
    })

    return row
  })

  const palette = ['#fafafa', '#a1a1aa', '#52525b']

  return (
    <div className="space-y-6">
      <div className="h-[360px] rounded-2xl border border-zinc-800 bg-zinc-900/70 p-4">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={chartData}>
            <CartesianGrid stroke="#27272a" strokeDasharray="3 3" />
            <XAxis dataKey="metric" stroke="#a1a1aa" tickLine={false} axisLine={false} />
            <YAxis stroke="#a1a1aa" tickLine={false} axisLine={false} />
            <Tooltip
              contentStyle={{
                backgroundColor: '#09090b',
                border: '1px solid #27272a',
                borderRadius: '12px',
                color: '#fafafa',
              }}
            />
            <Legend />
            {scenarios.map((scenario, index) => (
              <Bar
                key={scenario.name}
                dataKey={scenario.name}
                fill={palette[index % palette.length]}
                radius={[6, 6, 0, 0]}
              />
            ))}
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div className="grid gap-4 lg:grid-cols-3">
        {scenarios.map((scenario) => (
          <div
            key={scenario.name}
            className="rounded-2xl border border-zinc-800 bg-zinc-900/70 p-5 shadow-lg shadow-black/20"
          >
            <div className="text-xs uppercase tracking-[0.12em] text-zinc-500">
              {scenario.name.replaceAll('_', ' ')}
            </div>
            <p className="mt-3 text-sm text-zinc-300">{scenario.description}</p>

            {!!scenario.assumptions?.length && (
              <div className="mt-4 space-y-2">
                <div className="text-xs uppercase tracking-[0.12em] text-zinc-500">
                  Supuestos
                </div>
                <ul className="space-y-2 text-sm text-zinc-400">
                  {scenario.assumptions.map((assumption) => (
                    <li key={assumption}>• {assumption}</li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  )
}
